import requests
import json

# create a service
url = 'http://localhost:8001/services/'
data = {
    "name": "service-1",
    "host": "httpbin.org"
}
response = requests.post(url, data=json.dumps(data))
print("Service created")

# create a route for the service
url = 'http://localhost:8001/services/' + data['name'] + '/routes'
data = {
    "paths": [
        "/get"
    ]
}
response = requests.post(url, data=json.dumps(data))
print("Route created")

# create an upstream target for the route
url = 'http://localhost:8001/services/' + data['name'] + '/targets'
data = {
    "target": "httpbin.org:80"
}
response = requests.post(url, data=json.dumps(data))
print("Target created")